#include <iostream>
using namespace std;

int main() {
   // Declare variables
   double num1, num2;
   char operation;

   // Ask for user input
   cout << "Enter the first number: ";
   cin >> num1;
   cout << "Enter an operation (+, -, *, /): ";
   cin >> operation;
   cout << "Enter the second number: ";
   cin >> num2;

   // Calculate result based on user input
   switch(operation) {
      case '+':
         cout << "Result: " << num1 + num2;
         break;
      case '-':
         cout << "Result: " << num1 - num2;
         break;
      case '*':
         cout << "Result: " << num1 * num2;
         break;
      case '/':
         cout << "Result: " << num1 / num2;
         break;
      default:
         cout << "Invalid operation";
         break;
   }

   return 0;
}
```

This code prompts the user to enter two numbers and an operation (+, -, *, or /) to perform on those numbers. It then calculates the result and displays it to the user. Note that this is a basic example and doesn't include error handling or user interface elements.

